// Get pdfAttachmentKey for THIS pdf (item-linked through the chain)
let pdfAttachmentKey = null;
try { pdfAttachmentKey = $('Merge Email + PDF Data').item.json.pdfAttachmentKey; } catch(e) {}
// Vendor id via item linking
let vendorId = null;
try { vendorId = $('Check Vendor Exists1').item.json.vendor.id; } catch(e) {}

// Message id (same for all PDFs in this email)
let gmailId = null;
try { gmailId = $('Merge Email + PDF Data').item.json.gmailMessageId; } catch(e) {
  try { gmailId = $('Microsoft Outlook Trigger').first().json.id || null; } catch(e2) {}
}

const raw   = $input.item.json.output ?? '';
const clean = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let extracted;
try {
  extracted = JSON.parse(clean);
} catch(e) {
  extracted = { invoice_number: null, amount: null, taxable_amount: null,
    billing_period_start: null, billing_period_end: null,
    line_items: [], anomaly_flags: ['JSON parse failed — manual review required'] };
}

const lineItems        = extracted.line_items ?? [];
const calculatedAmount = lineItems.reduce((s, i) => s + (Number(i.total) || 0), 0);
const amount           = extracted.amount ?? extracted.total_amount ?? (calculatedAmount > 0 ? calculatedAmount : 0);
const taxableAmount    = extracted.taxable_amount ?? extracted.amount ?? (calculatedAmount > 0 ? calculatedAmount : 0);

return {
  json: {
    vendor_id:             vendorId,
    invoice_number:        extracted.invoice_number,
    amount:                amount,
    taxable_amount:        taxableAmount,
    cgst_amount:           extracted.cgst_amount  ?? 0,
    sgst_amount:           extracted.sgst_amount  ?? 0,
    igst_amount:           extracted.igst_amount  ?? 0,
    billing_period_start:  extracted.billing_period_start,
    billing_period_end:    extracted.billing_period_end,
    line_items:            JSON.parse(JSON.stringify(lineItems)),
    anomaly_flags:         JSON.parse(JSON.stringify(extracted.anomaly_flags ?? [])),
    status:                'PENDING_L1',
    pdf_attachment_key:    pdfAttachmentKey,
    gmail_message_id:      gmailId
  }
};

const vendorResult = $input.item.json;

let vendorFound = false;
let vendor = null;
if (vendorResult && vendorResult.id) {
  vendorFound = true;
  vendor = vendorResult;
}

// Email metadata is the same for every PDF in this email
const emailData = $('Microsoft Outlook Trigger').first().json;

const senderEmail = emailData.from?.emailAddress?.address ||
                    emailData.sender?.emailAddress?.address || '';
const senderName  = emailData.from?.emailAddress?.name ||
                    emailData.sender?.emailAddress?.name || '';
const subject          = emailData.subject || '(no subject)';
const emailReceivedAt  = emailData.receivedDateTime || emailData.date || new Date().toISOString();
const messageId        = emailData.id || emailData.internetMessageId || '';

// Per-PDF text — item-linked through the chain
const mergedData = $('Merge Email + PDF Data').item.json;
const pdfText    = mergedData.pdfText  || '';
const pdfPages   = mergedData.pdfPages || 0;

return {
  json: { vendorFound, vendor, senderEmail, senderName, subject,
          emailReceivedAt, messageId, pdfText, pdfPages }
};

const item = $input.item.json;

const body = JSON.stringify({
  model: 'claude-sonnet-4-6',
  max_tokens: 10,
  stream: false,
  system: 'You are a document classifier. Reply with ONE word only: CONTRACT, BILL, or OTHER.',
  messages: [{
    role: 'user',
    content: 'Email subject: ' + (item.subject || '') +
             '\n\nDocument text:\n' + (item.pdfText || '').substring(0, 2000) +
             '\n\nONE word only:'
  }]
});

return { json: { ...item, claudeBody: body } };

