const originalEmail = $('Extract Email Metadata2').first();

return [{
  json: originalEmail.json,
  binary: originalEmail.binary
}];

function generateToken() {
  let t = '';
  const chars = '0123456789abcdef';
  for (let i = 0; i < 64; i++) t += chars[Math.floor(Math.random() * 16)];
  return t;
}

// Item-linked bill ID for this specific PDF's bill
const billId = $('Supabase — Insert Bill1').item.json.id;
const baseUrl = 'https://mirragiohimanshu.app.n8n.cloud/webhook/approval';

const approveToken = generateToken();
const rejectToken  = generateToken();

return {
  json: {
    bill_id:      billId,
    approveToken: approveToken,
    rejectToken:  rejectToken,
    approveLink:  baseUrl + '?token=' + approveToken,
    rejectLink:   baseUrl + '?token=' + rejectToken
  }
};

// Single dedup check result for this invoice
const dupResult = $input.item.json;

let isDuplicate    = false;
let existingBillId = null;

if (Array.isArray(dupResult) && dupResult.length > 0) {
  isDuplicate    = true;
  existingBillId = dupResult[0].id;
} else if (dupResult && dupResult.id) {
  isDuplicate    = true;
  existingBillId = dupResult.id;
}

const billData = $('Prepare Bill for Insert').item.json;

return {
  json: { ...billData, isDuplicate, existingBillId }
};

// Emit one item per PDF found in this email — no more silent drop of extras.
const binary      = $input.first().binary || {};
const jsonData    = $input.first().json;
const binaryKeys  = Object.keys(binary);

const pdfItems = [];
for (const key of binaryKeys) {
  const b = binary[key];
  const isPdf =
    b.mimeType === 'application/pdf' ||
    b.fileName?.toLowerCase().endsWith('.pdf') ||
    (b.mimeType === 'application/octet-stream' && b.fileName?.toLowerCase().endsWith('.pdf'));
  if (isPdf) {
    pdfItems.push({
      json: {
        ...jsonData,
        pdfAttachmentKey: key,
        pdfFileName: b.fileName,
        noPdfFound: false,
        allAttachmentKeys: binaryKeys,
        totalAttachments: binaryKeys.length
      },
      binary: binary
    });
  }
}

if (pdfItems.length === 0) {
  return [{
    json: { ...jsonData, pdfAttachmentKey: null, noPdfFound: true,
            allAttachmentKeys: binaryKeys, totalAttachments: binaryKeys.length },
    binary: binary
  }];
}

return pdfItems;

return [{
  json: {
    vendorFound: $json.vendorFound,
    vendor: $json.vendor,
    senderEmail: $json.senderEmail,
    message: "DEBUG: Check if vendor was found above"
  }
}];

const pdfData   = $input.item.json;
const emailData = $('Collect All PDFs').item.json;

return {
  json: {
    senderEmail:      emailData.senderEmail,
    senderName:       emailData.senderName,
    subject:          emailData.subject,
    emailReceivedAt:  emailData.emailReceivedAt,
    gmailMessageId:   emailData.gmailMessageId,
    hasAttachment:    emailData.hasAttachment,
    pdfAttachmentKey: emailData.pdfAttachmentKey,
    pdfFileName:      emailData.pdfFileName,
    pdfText:          pdfData.text  || '',
    pdfPages:         pdfData.numpages || 0
  },
  binary: $input.item.binary
};

const billData   = $input.item.json;
const billArr    = Array.isArray(billData) ? billData : [billData];
const bill       = billArr[0] || {};
const billId     = bill.id            || null;
const invoiceNo  = bill.invoice_number || null;

// Get pdfAttachmentKey carried through Prepare Bill for Insert (item-linked)
// This correctly resolves per-item because both nodes are in the same chain
// after 'Collect All PDFs', so item linking works.
let pdfKey = null;
try { pdfKey = $('Prepare Bill for Insert').item.json.pdf_attachment_key; } catch(e) {}

// Search Collect All PDFs items by key — avoids item-linking boundary issue
// ($('Collect All PDFs').item always returns item 0 because it emits N from 1 input)
const allPdfItems = $('Collect All PDFs').all();
const matchItem   = allPdfItems.find(i => i.json.pdfAttachmentKey === pdfKey)
                    || allPdfItems[0];
const origBinary  = matchItem.binary || {};

const safeName    = (invoiceNo || billId || 'bill').toString().replace(/[^a-zA-Z0-9_\-]/g, '_');
const storagePath = 'Invoice_' + safeName + '.pdf';

return {
  json:   { bill_id: billId, invoice_number: invoiceNo, storagePath },
  binary: (pdfKey && origBinary[pdfKey]) ? { pdfData: origBinary[pdfKey] } : {}
};

const storagePath  = $('Prepare PDF Upload').item.json.storagePath;
const billId       = $('Prepare PDF Upload').item.json.bill_id;
const uploadResult = $input.item.json || {};

const uploadOk = !!(uploadResult.Key || uploadResult.path || uploadResult.Id);
const pdfUrl   = uploadOk
  ? 'https://ydoitzgqavfmbyrirxxe.supabase.co/storage/v1/object/public/bills/' + storagePath
  : null;

return { json: { bill_id: billId, bill_pdf_url: pdfUrl } };
